import {createContext, useContext} from 'react';

export interface KeyboardNavContextValue {
    register: (id: string, ref: any) => void;
    unregister: (id: string) => void;
    setElementsOrder: (ids: string[]) => void;
    getNavProps: (id: string) => Record<string, any>;
}

const noop = () => {};
const noopNavProps = { register: noop, unregister: noop, setElementsOrder: noop, getNavProps: () => ({}) };

// Web no-op context
export const KeyboardNavContext = createContext<KeyboardNavContextValue>(noopNavProps);

export const useKeyboardNav = () => useContext(KeyboardNavContext);

/** Web no-op — keyboard navigation is only needed on native. */
export function useKeyboardNavProvider(): KeyboardNavContextValue {
    return noopNavProps;
}
